  var recentClosings = (data.recentClosings || []).slice();
  
  // Compute closing windows — most recent first, sorted by closeDate desc
  var today = new Date();
  function daysAgo(dateStr) {
    if (!dateStr) return 9999;
    var d = new Date(dateStr);
    return Math.floor((today - d) / (1000 * 60 * 60 * 24));
  }
  var closings30 = recentClosings.filter(function(c){ return daysAgo(c.closeDate) <= 30; });
  var closings60 = recentClosings.filter(function(c){ return daysAgo(c.closeDate) <= 60; });
  var closings90 = recentClosings.filter(function(c){ return daysAgo(c.closeDate) <= 90; });
  
  // Median sold price (last 90)
  function medianN(arr, key) {
    var vals = arr.map(function(x){ return x[key]; }).filter(function(v){ return v && !isNaN(v); }).sort(function(a,b){ return a-b; });
    if (vals.length === 0) return 0;
    var mid = Math.floor(vals.length / 2);
    return vals.length % 2 === 0 ? (vals[mid-1] + vals[mid]) / 2 : vals[mid];
  }
  var medSold30 = medianN(closings30, 'soldPrice');
  var medSold90 = medianN(closings90, 'soldPrice');
  var medRatio90 = medianN(closings90, 'soldRatio');
