  var newActives = actives.filter(function(l){ return l.isNewListing || (l.dom !== undefined && l.dom <= 7); });
  var priceCutActives = actives.filter(function(l){ return l.isPriceReduced; });

  // Apply the status filter
  var displayedActives = actives;
  if (statusFilter === 'new') displayedActives = newActives;
  else if (statusFilter === 'pricecut') displayedActives = priceCutActives;
  else if (statusFilter === 'ucb') displayedActives = ucbList;
  else if (statusFilter === 'contingent') displayedActives = contingents;
  else if (statusFilter === 'pending') displayedActives = pendings;
  else if (statusFilter === 'comingsoon') displayedActives = comingSoon;

