// ── COST OF OWNERSHIP CALCULATOR ─────────────────────────────────────
function recalcCost() {
  var price = parseFloat(document.getElementById('costHomePrice').value) || 375000;
  var people = parseInt(document.getElementById('costPeople').value) || 2;
  var hoa = parseFloat(document.getElementById('costHOA').value) || 0;
  var golf = parseInt(document.getElementById('costGolf').value) || 0;
  var snow = document.getElementById('costSnowbird').value;
  var taxArea = document.getElementById('costInTown').value;

  // Property tax: roughly 0.59% in unincorporated PebbleCreek, 0.72% in Surprise city
  var taxRate = taxArea === 'surprise' ? 0.0072 : 0.0059;
  var propertyTax = price * taxRate;

  // Recreation card
  var recCard = people * 570;

  // Insurance — roughly 0.24% of home value for AZ retirees
  var insurance = price * 0.0024;

  // Utilities — full year ~$2,400 for a couple, snowbird ~$1,500
  var utilities = snow === 'snow' ? 1500 : 2400;

  // Internet/cable
  var internet = 1200;

  // HOA (monthly to annual)
  var hoaAnnual = hoa * 12;

  // Golf
  var golfCost = 0;
  if (golf === 1) golfCost = 1800;
  else if (golf === 2) golfCost = 3600;
  else if (golf === 3) golfCost = 8000;

  var total = propertyTax + recCard + insurance + utilities + internet + hoaAnnual + golfCost;

  function fmt(n) { return '$' + Math.round(n).toLocaleString(); }

  var html =
    '<div class="cost-result-label">Estimated Annual Cost</div>' +
    '<div class="cost-result-total">' + fmt(total) + '</div>' +
    '<div class="cost-result-sub">' + fmt(total / 12) + '/month average · for a ' + fmt(price) + ' home</div>' +
    '<div class="cost-breakdown">' +
      '<div class="cost-line"><span class="cost-line-label">Property Tax (' + (taxRate * 100).toFixed(2) + '%)</span><span class="cost-line-amount">' + fmt(propertyTax) + '</span></div>' +
      '<div class="cost-line"><span class="cost-line-label">Recreation Card (' + people + ' person' + (people===1?'':'s') + ')</span><span class="cost-line-amount">' + fmt(recCard) + '</span></div>' +
      '<div class="cost-line"><span class="cost-line-label">Home Insurance</span><span class="cost-line-amount">' + fmt(insurance) + '</span></div>' +
      '<div class="cost-line"><span class="cost-line-label">Utilities (' + (snow === 'snow' ? 'snowbird' : 'year-round') + ')</span><span class="cost-line-amount">' + fmt(utilities) + '</span></div>' +
      '<div class="cost-line"><span class="cost-line-label">Internet / Cable</span><span class="cost-line-amount">' + fmt(internet) + '</span></div>' +
      (hoaAnnual > 0 ? '<div class="cost-line"><span class="cost-line-label">Subdivision HOA</span><span class="cost-line-amount">' + fmt(hoaAnnual) + '</span></div>' : '') +
      (golfCost > 0 ? '<div class="cost-line"><span class="cost-line-label">Golf</span><span class="cost-line-amount">' + fmt(golfCost) + '</span></div>' : '') +
      '<div class="cost-line cost-line-total"><span class="cost-line-label">Total per year</span><span class="cost-line-amount">' + fmt(total) + '</span></div>' +
    '</div>';

  document.getElementById('costResult').innerHTML = html;
}

// Initialize the cost calc on page load
window.addEventListener('DOMContentLoaded', function(){
  if (document.getElementById('costResult')) recalcCost();
  if (document.getElementById('activeGrid')) renderActiveListings();
});

function shareCurrentView() {
  var params = new URLSearchParams();
  params.set('year', currentYear);
  params.set('month', currentTab);
  var url = window.location.origin + window.location.pathname + '?' + params.toString();
  // Copy to clipboard
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(url).then(function(){
      flashShareConfirm('Link copied! 📋');
    }).catch(function(){
      flashShareConfirm('Copy this: ' + url);
    });
  } else {
    // Fallback for older browsers
    try {
      var ta = document.createElement('textarea');
      ta.value = url;
      ta.style.position = 'fixed';
      ta.style.opacity = '0';
      document.body.appendChild(ta);
      if (typeof ta.select === 'function') ta.select();
      var ok = false;
      try { ok = document.execCommand('copy'); } catch(e) {}
      document.body.removeChild(ta);
      flashShareConfirm(ok ? 'Link copied! 📋' : 'Copy this: ' + url);
    } catch(e) {
      flashShareConfirm('Copy this: ' + url);
    }
  }
}

function flashShareConfirm(msg) {
  var el = document.createElement('div');
  el.textContent = msg;
  el.style.cssText = 'position:fixed;bottom:24px;left:50%;transform:translateX(-50%);background:var(--green);color:#fff;padding:12px 24px;border-radius:24px;font-weight:700;font-size:13px;z-index:9999;box-shadow:0 8px 24px rgba(0,0,0,.3);animation:share-flash 2.4s ease-out forwards;';
  document.body.appendChild(el);
  setTimeout(function(){ if (el.parentNode) el.parentNode.removeChild(el); }, 2400);
}

// Previously positioned the controls bar below the (then-sticky) hero.
// Now that only the picker bar is sticky, this is a no-op kept for backwards compat.
function adjustControlsTop() { /* no-op */ }
window.addEventListener('load', adjustControlsTop);
window.addEventListener('resize', adjustControlsTop);
// Re-adjust after tab switch since hero height may change
var origSwitchTab = switchTab;
switchTab = function(key) {
  origSwitchTab(key);
  setTimeout(adjustControlsTop, 50);
  updatePermalink();
};

// Wire permalink updates into year switching too
if (typeof switchYear === 'function') {
  var origSwitchYear = switchYear;
  switchYear = function(year) {
    origSwitchYear(year);
    setTimeout(updatePermalink, 50);
  };
}



